mapper.select:
SELECT * FROM agent_workflow_stage
WHERE workflow_code = #{workflowCode}
ORDER BY stage_order ASC

SELECT * FROM agent_workflow_stage
WHERE workflow_code = #{workflowCode}
  AND code = #{stageCode}
LIMIT 1

SELECT * FROM agent_workflow_stage
WHERE workflow_code = #{workflowCode}
  AND stage_order > #{currentOrder}
ORDER BY stage_order ASC
LIMIT 1

SELECT * FROM agent_workflow_route_rule
WHERE intent_code = #{intentCode}
LIMIT 1

SELECT * FROM workbench_layout_config
WHERE workflow_code = #{workflowCode}
  AND stage_code = #{stageCode}
  AND enabled = 1
LIMIT 1
